CREATE POLICY "experts_self_update" ON "public"."experts" FOR UPDATE TO authenticated USING ((id = auth.uid())) WITH CHECK (((id = auth.uid()) AND (is_approved = ( SELECT experts_1.is_approved
   FROM experts experts_1
  WHERE (experts_1.id = auth.uid())))));

CREATE POLICY "expert_availability_read_all" ON "public"."expert_availability" FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM experts
  WHERE ((experts.id = expert_availability.expert_id) AND (experts.is_approved = true)))));

CREATE POLICY "chat_rooms_participant_select" ON "public"."chat_rooms" FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM chat_participants
  WHERE ((chat_participants.room_id = chat_rooms.id) AND (chat_participants.user_id = auth.uid())))));

CREATE POLICY "messages_participant_select" ON "public"."messages" FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM chat_participants
  WHERE ((chat_participants.room_id = messages.room_id) AND (chat_participants.user_id = auth.uid())))));

CREATE POLICY "messages_sender_insert" ON "public"."messages" FOR INSERT TO authenticated WITH CHECK (((sender_id = auth.uid()) AND (EXISTS ( SELECT 1
   FROM chat_participants
  WHERE ((chat_participants.room_id = messages.room_id) AND (chat_participants.user_id = auth.uid()))))));

CREATE POLICY "chat_participants_read" ON "public"."chat_participants" FOR SELECT TO authenticated USING (((user_id = auth.uid()) OR (EXISTS ( SELECT 1
   FROM chat_participants cp
  WHERE ((cp.room_id = chat_participants.room_id) AND (cp.user_id = auth.uid()))))));

CREATE POLICY "users_read_appointment_counterpart" ON "public"."users" FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM appointments a
  WHERE (((a.user_id = users.id) AND (a.expert_id = auth.uid())) OR ((a.expert_id = users.id) AND (a.user_id = auth.uid()))))));

CREATE POLICY "users_read_approved_expert_profile" ON "public"."users" FOR SELECT TO authenticated USING ((EXISTS ( SELECT 1
   FROM experts e
  WHERE ((e.id = users.id) AND (e.is_approved = true)))));
